// HBM read-bandwidth microbenchmark for AMD MI35X (gfx950 / CDNA4)
//
// Strategy: allocate a large (multi-GiB) buffer on the device, and run a
// kernel that streams over it once per launch using coalesced float4 loads.
// Each thread grid-strides over the buffer, reduces what it reads into a
// register accumulator, and at the very end of the kernel (never during the
// hot loop) does a single atomicAdd of its partial sum into a tiny global
// output buffer. This keeps the reads live (prevents dead-code elimination)
// while contributing a negligible amount of write traffic relative to the
// multi-GiB of reads, so the measurement is effectively read-only bandwidth.
//
// We warm up, then time many back-to-back launches with hipEvents and report
// the median iteration time, from which we compute GB/s = bytes / time.

#include <hip/hip_runtime.h>
#include <cstdio>
#include <cstdlib>
#include <vector>
#include <algorithm>
#include <cstdint>

#define HIP_CHECK(cmd) do { \
    hipError_t e = (cmd); \
    if (e != hipSuccess) { \
        fprintf(stderr, "HIP error %s at %s:%d\n", hipGetErrorString(e), __FILE__, __LINE__); \
        exit(1); \
    } \
} while (0)

// Streaming read kernel: grid-stride loop over float4 elements, one full
// pass over the buffer per launch. Vectorized 16B loads for coalescing.
__global__ void stream_read_kernel(const float4* __restrict__ in,
                                    uint64_t n_vec4,
                                    float* __restrict__ sink)
{
    uint64_t idx = (uint64_t)blockIdx.x * blockDim.x + threadIdx.x;
    uint64_t stride = (uint64_t)gridDim.x * blockDim.x;

    float4 acc = make_float4(0.f, 0.f, 0.f, 0.f);

    for (uint64_t i = idx; i < n_vec4; i += stride) {
        float4 v = in[i];
        acc.x += v.x;
        acc.y += v.y;
        acc.z += v.z;
        acc.w += v.w;
    }

    // Reduce within block via shared memory, then a single atomicAdd per
    // block into a tiny sink buffer. This is negligible write traffic
    // (a few KB total) compared to the multi-GiB of reads, and it keeps
    // the compiler from eliminating the read loop as dead code.
    __shared__ float sx[256], sy[256], sz[256], sw[256];
    int tid = threadIdx.x;
    sx[tid] = acc.x; sy[tid] = acc.y; sz[tid] = acc.z; sw[tid] = acc.w;
    __syncthreads();

    for (int s = blockDim.x / 2; s > 0; s >>= 1) {
        if (tid < s) {
            sx[tid] += sx[tid + s];
            sy[tid] += sy[tid + s];
            sz[tid] += sz[tid + s];
            sw[tid] += sw[tid + s];
        }
        __syncthreads();
    }

    if (tid == 0) {
        atomicAdd(&sink[0], sx[0] + sy[0] + sz[0] + sw[0]);
    }
}

static double median(std::vector<double> v) {
    std::sort(v.begin(), v.end());
    size_t n = v.size();
    if (n % 2 == 1) return v[n / 2];
    return 0.5 * (v[n / 2 - 1] + v[n / 2]);
}

int main(int argc, char** argv) {
    // Default: 3 GiB buffer of floats (well above any cache size, and above
    // the required >= 2 GiB working set).
    uint64_t buffer_bytes = (argc > 1) ? strtoull(argv[1], nullptr, 10)
                                        : (3ull * 1024 * 1024 * 1024);
    int n_iters = (argc > 2) ? atoi(argv[2]) : 30;
    int n_warmup = (argc > 3) ? atoi(argv[3]) : 5;

    uint64_t n_floats = buffer_bytes / sizeof(float);
    uint64_t n_vec4 = n_floats / 4;
    buffer_bytes = n_vec4 * sizeof(float4); // exact, vec4-aligned

    HIP_CHECK(hipSetDevice(0));

    float4* d_buf = nullptr;
    float* d_sink = nullptr;
    HIP_CHECK(hipMalloc(&d_buf, buffer_bytes));
    HIP_CHECK(hipMalloc(&d_sink, sizeof(float)));
    HIP_CHECK(hipMemset(d_buf, 1, buffer_bytes)); // touch/init pages, arbitrary bits
    HIP_CHECK(hipMemset(d_sink, 0, sizeof(float)));

    int threads = 256;
    // Use a large grid to saturate the memory system (256 CUs on gfx950).
    // Many more blocks than can be resident at once so the grid-stride loop
    // still does a single full pass, well-distributed across all CUs.
    int blocks = 1 << 15; // 32768 blocks * 256 threads = ~8.39M threads

    hipEvent_t start, stop;
    HIP_CHECK(hipEventCreate(&start));
    HIP_CHECK(hipEventCreate(&stop));

    // Warmup
    for (int i = 0; i < n_warmup; ++i) {
        stream_read_kernel<<<blocks, threads>>>(d_buf, n_vec4, d_sink);
    }
    HIP_CHECK(hipDeviceSynchronize());

    std::vector<double> times_ms;
    times_ms.reserve(n_iters);

    for (int i = 0; i < n_iters; ++i) {
        HIP_CHECK(hipEventRecord(start));
        stream_read_kernel<<<blocks, threads>>>(d_buf, n_vec4, d_sink);
        HIP_CHECK(hipEventRecord(stop));
        HIP_CHECK(hipEventSynchronize(stop));
        float ms = 0.f;
        HIP_CHECK(hipEventElapsedTime(&ms, start, stop));
        times_ms.push_back((double)ms);
    }

    double med_ms = median(times_ms);
    double gbps = ((double)buffer_bytes / 1e9) / (med_ms / 1e3);

    // Make sure the sink is actually consumed so nothing upstream gets
    // optimized away; copy it back (tiny, 4 bytes).
    float sink_val = 0.f;
    HIP_CHECK(hipMemcpy(&sink_val, d_sink, sizeof(float), hipMemcpyDeviceToHost));

    fprintf(stderr, "buffer_bytes=%llu n_vec4=%llu iters=%d median_ms=%.4f sink=%g\n",
            (unsigned long long)buffer_bytes, (unsigned long long)n_vec4,
            n_iters, med_ms, sink_val);

    printf("HBM_BANDWIDTH_GBPS=%.2f\n", gbps);
    printf("buffer_bytes=%llu\n", (unsigned long long)buffer_bytes);

    HIP_CHECK(hipFree(d_buf));
    HIP_CHECK(hipFree(d_sink));
    return 0;
}

