// Strategy: allocate a large (multi-GiB) buffer on the device and run a
// kernel that streams over it once per launch using coalesced, 4x-unrolled
// float4 loads (16B accesses, grid-stride, 4 independent loads per iteration
// for instruction-level parallelism / more outstanding requests). Each
// thread reduces what it reads into a register accumulator; at the very end
// of the kernel (never inside the hot loop) each block writes its partial
// sum to a distinct slot of a tiny per-block sink buffer. This keeps the
// reads live (prevents dead-code elimination) while adding a negligible
// amount of write traffic (a few KB total) relative to the multi-GiB of
// reads, so the measurement is effectively read-only bandwidth.
//
// We warm up, then time many back-to-back launches with hipEvents and report
// the median iteration time, from which we compute GB/s = bytes / time.

#include <hip/hip_runtime.h>
#include <cstdio>
#include <cstdlib>
#include <vector>
#include <algorithm>
#include <cstdint>

#define HIP_CHECK(cmd) do { \
    hipError_t e = (cmd); \
    if (e != hipSuccess) { \
        fprintf(stderr, "HIP error %s at %s:%d\n", hipGetErrorString(e), __FILE__, __LINE__); \
        exit(1); \
    } \
} while (0)

// Streaming read kernel: grid-stride loop over float4 elements, 4x unrolled
// for ILP, one full pass over the buffer per launch. Vectorized 16B loads
// for coalescing.
__global__ void stream_read_kernel(const float4* __restrict__ in,
                                    uint64_t n_vec4,
                                    float* __restrict__ sink)
{
    uint64_t idx = (uint64_t)blockIdx.x * blockDim.x + threadIdx.x;
    uint64_t stride = (uint64_t)gridDim.x * blockDim.x;

    float4 acc = make_float4(0.f, 0.f, 0.f, 0.f);
    uint64_t i = idx;

    for (; i + 3 * stride < n_vec4; i += 4 * stride) {
        float4 v0 = in[i];
        float4 v1 = in[i + stride];
        float4 v2 = in[i + 2 * stride];
        float4 v3 = in[i + 3 * stride];
        acc.x += v0.x + v1.x + v2.x + v3.x;
        acc.y += v0.y + v1.y + v2.y + v3.y;
        acc.z += v0.z + v1.z + v2.z + v3.z;
        acc.w += v0.w + v1.w + v2.w + v3.w;
    }
    for (; i < n_vec4; i += stride) {
        float4 v = in[i];
        acc.x += v.x;
        acc.y += v.y;
        acc.z += v.z;
        acc.w += v.w;
    }

    // Reduce within block via shared memory, then a single plain store per
    // block into a distinct slot of a tiny sink buffer (no atomics needed
    // since each block owns its own slot). This is negligible write traffic
    // (blocks * 4 bytes total) compared to the multi-GiB of reads, and it
    // keeps the compiler from eliminating the read loop as dead code.
    __shared__ float sx[256], sy[256], sz[256], sw[256];
    int tid = threadIdx.x;
    sx[tid] = acc.x; sy[tid] = acc.y; sz[tid] = acc.z; sw[tid] = acc.w;
    __syncthreads();

    for (int s = blockDim.x / 2; s > 0; s >>= 1) {
        if (tid < s) {
            sx[tid] += sx[tid + s];
            sy[tid] += sy[tid + s];
            sz[tid] += sz[tid + s];
            sw[tid] += sw[tid + s];
        }
        __syncthreads();
    }

    if (tid == 0) {
        sink[blockIdx.x] = sx[0] + sy[0] + sz[0] + sw[0];
    }
}

static double median(std::vector<double> v) {
    std::sort(v.begin(), v.end());
    size_t n = v.size();
    if (n % 2 == 1) return v[n / 2];
    return 0.5 * (v[n / 2 - 1] + v[n / 2]);
}

int main(int argc, char** argv) {
    // Default: 3 GiB buffer of floats (well above any cache size, and above
    // the required >= 2 GiB working set).
    uint64_t buffer_bytes = (argc > 1) ? strtoull(argv[1], nullptr, 10)
                                        : (3ull * 1024 * 1024 * 1024);
    int n_iters = (argc > 2) ? atoi(argv[2]) : 30;
    int n_warmup = (argc > 3) ? atoi(argv[3]) : 5;

    uint64_t n_floats = buffer_bytes / sizeof(float);
    uint64_t n_vec4 = n_floats / 4;
    buffer_bytes = n_vec4 * sizeof(float4); // exact, vec4-aligned

    HIP_CHECK(hipSetDevice(0));

    int threads = 256;
    // Large grid to saturate the memory system across all CUs (256 CUs on
    // gfx950) while leaving enough grid-stride work per thread that the
    // kernel runs long enough to time accurately.
    int blocks = 8192;

    float4* d_buf = nullptr;
    float* d_sink = nullptr;
    HIP_CHECK(hipMalloc(&d_buf, buffer_bytes));
    HIP_CHECK(hipMalloc(&d_sink, sizeof(float) * blocks));
    HIP_CHECK(hipMemset(d_buf, 1, buffer_bytes)); // touch/init pages, arbitrary bits
    HIP_CHECK(hipMemset(d_sink, 0, sizeof(float) * blocks));

    hipEvent_t start, stop;
    HIP_CHECK(hipEventCreate(&start));
    HIP_CHECK(hipEventCreate(&stop));

    // Warmup
    for (int i = 0; i < n_warmup; ++i) {
        stream_read_kernel<<<blocks, threads>>>(d_buf, n_vec4, d_sink);
    }
    HIP_CHECK(hipDeviceSynchronize());

    std::vector<double> times_ms;
    times_ms.reserve(n_iters);

    for (int i = 0; i < n_iters; ++i) {
        HIP_CHECK(hipEventRecord(start));
        stream_read_kernel<<<blocks, threads>>>(d_buf, n_vec4, d_sink);
        HIP_CHECK(hipEventRecord(stop));
        HIP_CHECK(hipEventSynchronize(stop));
        float ms = 0.f;
        HIP_CHECK(hipEventElapsedTime(&ms, start, stop));
        times_ms.push_back((double)ms);
    }

    double med_ms = median(times_ms);
    double gbps = ((double)buffer_bytes / 1e9) / (med_ms / 1e3);

    // Make sure the sink is actually consumed so nothing upstream gets
    // optimized away; copy back the first slot (tiny, 4 bytes).
    float sink_val = 0.f;
    HIP_CHECK(hipMemcpy(&sink_val, d_sink, sizeof(float), hipMemcpyDeviceToHost));

    fprintf(stderr, "buffer_bytes=%llu n_vec4=%llu blocks=%d threads=%d iters=%d median_ms=%.4f sink=%g\n",
            (unsigned long long)buffer_bytes, (unsigned long long)n_vec4,
            blocks, threads, n_iters, med_ms, sink_val);

    printf("HBM_BANDWIDTH_GBPS=%.2f\n", gbps);
    printf("buffer_bytes=%llu\n", (unsigned long long)buffer_bytes);

    HIP_CHECK(hipFree(d_buf));
    HIP_CHECK(hipFree(d_sink));
    return 0;
}
